package com.aiaffiliate.infrastructure.notion.repository;
import com.aiaffiliate.application.reference.*;import com.aiaffiliate.domain.model.*;import com.aiaffiliate.domain.port.*;import com.aiaffiliate.infrastructure.notion.mapper.AffiliateProductNotionMapper;import com.aiaffiliate.notion.client.NotionClient;import java.util.*;
/** Notion 联盟产品 Repository Adapter。 */
public class NotionAffiliateProductRepository extends AbstractNotionRepository<AffiliateProduct> implements AffiliateProductRepository{
 public NotionAffiliateProductRepository(NotionClient c,AffiliateProductNotionMapper m,EntityReferenceRepository r,NotionDatabaseLocator l){super(c,m,r,l,"affiliate-products","Product ID");}
 public AffiliateProduct save(AffiliateProduct v){return saveEntity(v);}public AffiliateProduct update(AffiliateProduct v){return updateEntity(v);}public Optional<AffiliateProduct>findById(ProductId id){return findEntity(id.value());}public List<AffiliateProduct>findAll(){return findAllEntities();}public List<AffiliateProduct>findByStatus(ProductStatus s){return findAll().stream().filter(v->v.status()==s).toList();}public PageResult<AffiliateProduct>findPage(PageRequest p){return page(p);}public List<AffiliateProduct>findByPlatformAndCategory(AffiliatePlatform p,String c){return findAll().stream().filter(v->v.platform()==p&&v.category().equalsIgnoreCase(c)).toList();}public void archive(ProductId id){archiveEntity(id.value());}}
